import{_ as e,o as r,c as t,ag as h}from"./chunks/framework.ETe_P6d1.js";const u=JSON.parse('{"title":"专业调研报告内容：","description":"","frontmatter":{},"headers":[],"relativePath":"reports/邓一果/邓一果_邓一果_关于开平立园建筑建造材料与构造实的调研报告.md","filePath":"reports/邓一果/邓一果_邓一果_关于开平立园建筑建造材料与构造实的调研报告.md"}'),o={name:"reports/邓一果/邓一果_邓一果_关于开平立园建筑建造材料与构造实的调研报告.md"};function i(l,a,d,n,s,c){return r(),t("div",null,[...a[0]||(a[0]=[h('<p>XX XX XX XX XX XX</p><p>调研报告</p><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td>课程名称：</td><td>专业调研</td></tr><tr><td>课程负责人</td><td>石拓</td></tr><tr><td>实习日期：</td><td>2025.04.1至2025.04.2</td></tr><tr><td>学生所在学院：</td><td>设计学院</td></tr><tr><td>专业或班级：</td><td>环境设计一班</td></tr><tr><td>学生姓名：</td><td>邓一果</td></tr><tr><td>学生学号：</td><td>202430741829</td></tr><tr><td>带队教师：</td><td>石拓、王琛</td></tr></tbody></table><p>教务处 制</p><h1 id="专业调研报告内容" tabindex="-1">专业调研报告内容： <a class="header-anchor" href="#专业调研报告内容" aria-label="Permalink to &quot;专业调研报告内容：&quot;">​</a></h1><h1 id="开平立园建筑建造材料与构造实地调研报告" tabindex="-1">开平立园建筑建造材料与构造实地调研报告 <a class="header-anchor" href="#开平立园建筑建造材料与构造实地调研报告" aria-label="Permalink to &quot;开平立园建筑建造材料与构造实地调研报告&quot;">​</a></h1><h1 id="一、调研前言" tabindex="-1">一、调研前言 <a class="header-anchor" href="#一、调研前言" aria-label="Permalink to &quot;一、调研前言&quot;">​</a></h1><h1 id="本次调研是环境设计专业课程的实地教学实践-我们小组前往江门开平立园-对园内主体建筑、园林建筑、廊道、亭台等进行现场观察、细部拍摄、节点记录与构造草图绘制。报告以建造材料、结构体系、立面做法、节点构造、施工痕迹为核心内容-结合实地所见-去分析立园建筑真实的材料逻辑与营造方式" tabindex="-1">本次调研是环境设计专业课程的实地教学实践，我们小组前往江门开平立园，对园内主体建筑、园林建筑、廊道、亭台等进行现场观察、细部拍摄、节点记录与构造草图绘制。报告以建造材料、结构体系、立面做法、节点构造、施工痕迹为核心内容，结合实地所见，去分析立园建筑真实的材料逻辑与营造方式. <a class="header-anchor" href="#本次调研是环境设计专业课程的实地教学实践-我们小组前往江门开平立园-对园内主体建筑、园林建筑、廊道、亭台等进行现场观察、细部拍摄、节点记录与构造草图绘制。报告以建造材料、结构体系、立面做法、节点构造、施工痕迹为核心内容-结合实地所见-去分析立园建筑真实的材料逻辑与营造方式" aria-label="Permalink to &quot;本次调研是环境设计专业课程的实地教学实践，我们小组前往江门开平立园，对园内主体建筑、园林建筑、廊道、亭台等进行现场观察、细部拍摄、节点记录与构造草图绘制。报告以建造材料、结构体系、立面做法、节点构造、施工痕迹为核心内容，结合实地所见，去分析立园建筑真实的材料逻辑与营造方式.&quot;">​</a></h1><h1 id="开平立园由旅美华侨谢维立先生始建于20世纪20年代-是集住宅、园林、防御、社交功能于一体的近代侨乡私家园林。建筑最突出的特点是中式园林布局、岭南本土营造、西洋古典形式三者高度融合。在材料与构造上-它既保留了广府民居的传统做法-又大胆使用民国时期先进的钢筋混凝土技术-形成了独有的-侨乡建造体系-。通过本次实地调研-我们能更直观理解近代华侨建筑在材料选择、结构安全、气候适应、审美表达上的综合智慧-也为今后地域建筑设计、历史建筑保护与更新积累真实经验。" tabindex="-1">开平立园由旅美华侨谢维立先生始建于20世纪20年代，是集住宅、园林、防御、社交功能于一体的近代侨乡私家园林。建筑最突出的特点是中式园林布局、岭南本土营造、西洋古典形式三者高度融合。在材料与构造上，它既保留了广府民居的传统做法，又大胆使用民国时期先进的钢筋混凝土技术，形成了独有的“侨乡建造体系”。通过本次实地调研，我们能更直观理解近代华侨建筑在材料选择、结构安全、气候适应、审美表达上的综合智慧，也为今后地域建筑设计、历史建筑保护与更新积累真实经验。 <a class="header-anchor" href="#开平立园由旅美华侨谢维立先生始建于20世纪20年代-是集住宅、园林、防御、社交功能于一体的近代侨乡私家园林。建筑最突出的特点是中式园林布局、岭南本土营造、西洋古典形式三者高度融合。在材料与构造上-它既保留了广府民居的传统做法-又大胆使用民国时期先进的钢筋混凝土技术-形成了独有的-侨乡建造体系-。通过本次实地调研-我们能更直观理解近代华侨建筑在材料选择、结构安全、气候适应、审美表达上的综合智慧-也为今后地域建筑设计、历史建筑保护与更新积累真实经验。" aria-label="Permalink to &quot;开平立园由旅美华侨谢维立先生始建于20世纪20年代，是集住宅、园林、防御、社交功能于一体的近代侨乡私家园林。建筑最突出的特点是中式园林布局、岭南本土营造、西洋古典形式三者高度融合。在材料与构造上，它既保留了广府民居的传统做法，又大胆使用民国时期先进的钢筋混凝土技术，形成了独有的“侨乡建造体系”。通过本次实地调研，我们能更直观理解近代华侨建筑在材料选择、结构安全、气候适应、审美表达上的综合智慧，也为今后地域建筑设计、历史建筑保护与更新积累真实经验。&quot;">​</a></h1><h1 id="二、建筑整体结构与主体材料" tabindex="-1">二、建筑整体结构与主体材料 <a class="header-anchor" href="#二、建筑整体结构与主体材料" aria-label="Permalink to &quot;二、建筑整体结构与主体材料&quot;">​</a></h1><h1 id="从现场观察来看-立园主体建筑没有统一的单一结构-而是砖混承重与钢筋混凝土现浇混合使用-根据功能、造型、位置灵活搭配-这也是当时侨乡洋楼最常见、最务实的建造方式。" tabindex="-1">从现场观察来看，立园主体建筑没有统一的单一结构，而是砖混承重与钢筋混凝土现浇混合使用，根据功能、造型、位置灵活搭配，这也是当时侨乡洋楼最常见、最务实的建造方式。 <a class="header-anchor" href="#从现场观察来看-立园主体建筑没有统一的单一结构-而是砖混承重与钢筋混凝土现浇混合使用-根据功能、造型、位置灵活搭配-这也是当时侨乡洋楼最常见、最务实的建造方式。" aria-label="Permalink to &quot;从现场观察来看，立园主体建筑没有统一的单一结构，而是砖混承重与钢筋混凝土现浇混合使用，根据功能、造型、位置灵活搭配，这也是当时侨乡洋楼最常见、最务实的建造方式。&quot;">​</a></h1><h1 id="一-墙体结构-青砖砌筑为主-承重与围护清晰" tabindex="-1">（一）墙体结构：青砖砌筑为主，承重与围护清晰 <a class="header-anchor" href="#一-墙体结构-青砖砌筑为主-承重与围护清晰" aria-label="Permalink to &quot;（一）墙体结构：青砖砌筑为主，承重与围护清晰&quot;">​</a></h1><h1 id="园内所有建筑的外墙与主要内墙-均以青砖为主体砌筑材料。砖体尺寸规整-颜色青灰-质地密实-是岭南地区传统建房用砖。墙体厚度明显大于现代普通隔墙-一方面满足承重需求-另一方面在岭南炎热多雨气候下起到隔热、防风、防雨、防盗的作用-也延续了碉楼防御性的营造思路。" tabindex="-1">园内所有建筑的外墙与主要内墙，均以青砖为主体砌筑材料。砖体尺寸规整，颜色青灰，质地密实，是岭南地区传统建房用砖。墙体厚度明显大于现代普通隔墙，一方面满足承重需求，另一方面在岭南炎热多雨气候下起到隔热、防风、防雨、防盗的作用，也延续了碉楼防御性的营造思路。 <a class="header-anchor" href="#园内所有建筑的外墙与主要内墙-均以青砖为主体砌筑材料。砖体尺寸规整-颜色青灰-质地密实-是岭南地区传统建房用砖。墙体厚度明显大于现代普通隔墙-一方面满足承重需求-另一方面在岭南炎热多雨气候下起到隔热、防风、防雨、防盗的作用-也延续了碉楼防御性的营造思路。" aria-label="Permalink to &quot;园内所有建筑的外墙与主要内墙，均以青砖为主体砌筑材料。砖体尺寸规整，颜色青灰，质地密实，是岭南地区传统建房用砖。墙体厚度明显大于现代普通隔墙，一方面满足承重需求，另一方面在岭南炎热多雨气候下起到隔热、防风、防雨、防盗的作用，也延续了碉楼防御性的营造思路。&quot;">​</a></h1><h1 id="砌筑方式以顺丁砌法为主-错缝搭接-灰缝均匀、饱满-我们在墙角、窗侧、廊柱旁都能清晰看到砌筑痕迹。部分后期修补的墙体用红砖-但主体老墙均为青砖-砌筑工艺工整-能看出当年工匠手艺成熟。室内分隔墙同样以砖砌体为主-表面抹灰找平-不承担主要承重-只做空间划分。" tabindex="-1">砌筑方式以顺丁砌法为主，错缝搭接，灰缝均匀、饱满，我们在墙角、窗侧、廊柱旁都能清晰看到砌筑痕迹。部分后期修补的墙体用红砖，但主体老墙均为青砖，砌筑工艺工整，能看出当年工匠手艺成熟。室内分隔墙同样以砖砌体为主，表面抹灰找平，不承担主要承重，只做空间划分。 <a class="header-anchor" href="#砌筑方式以顺丁砌法为主-错缝搭接-灰缝均匀、饱满-我们在墙角、窗侧、廊柱旁都能清晰看到砌筑痕迹。部分后期修补的墙体用红砖-但主体老墙均为青砖-砌筑工艺工整-能看出当年工匠手艺成熟。室内分隔墙同样以砖砌体为主-表面抹灰找平-不承担主要承重-只做空间划分。" aria-label="Permalink to &quot;砌筑方式以顺丁砌法为主，错缝搭接，灰缝均匀、饱满，我们在墙角、窗侧、廊柱旁都能清晰看到砌筑痕迹。部分后期修补的墙体用红砖，但主体老墙均为青砖，砌筑工艺工整，能看出当年工匠手艺成熟。室内分隔墙同样以砖砌体为主，表面抹灰找平，不承担主要承重，只做空间划分。&quot;">​</a></h1><h1 id="墙体底部普遍做石材勒脚-高度大约在40—60厘米-用花岗岩条石砌筑-防止地面潮气、雨水侵蚀墙根-这是岭南建筑非常典型的防潮构造。" tabindex="-1">墙体底部普遍做石材勒脚，高度大约在40—60厘米，用花岗岩条石砌筑，防止地面潮气、雨水侵蚀墙根，这是岭南建筑非常典型的防潮构造。 <a class="header-anchor" href="#墙体底部普遍做石材勒脚-高度大约在40—60厘米-用花岗岩条石砌筑-防止地面潮气、雨水侵蚀墙根-这是岭南建筑非常典型的防潮构造。" aria-label="Permalink to &quot;墙体底部普遍做石材勒脚，高度大约在40—60厘米，用花岗岩条石砌筑，防止地面潮气、雨水侵蚀墙根，这是岭南建筑非常典型的防潮构造。&quot;">​</a></h1><h1 id="二-梁柱、拱廊、阳台-钢筋混凝土现浇" tabindex="-1">（二）梁柱、拱廊、阳台：钢筋混凝土现浇 <a class="header-anchor" href="#二-梁柱、拱廊、阳台-钢筋混凝土现浇" aria-label="Permalink to &quot;（二）梁柱、拱廊、阳台：钢筋混凝土现浇&quot;">​</a></h1><h1 id="立园最具-西洋风格-的部分-几乎都靠钢筋混凝土现浇实现。包括门厅立柱、回廊拱券、二层阳台、挑檐、天花梁板、宝瓶式栏杆、装饰性柱头与线脚等-全部为现场支模、绑扎钢筋、一次性浇筑成型。" tabindex="-1">立园最具“西洋风格”的部分，几乎都靠钢筋混凝土现浇实现。包括门厅立柱、回廊拱券、二层阳台、挑檐、天花梁板、宝瓶式栏杆、装饰性柱头与线脚等，全部为现场支模、绑扎钢筋、一次性浇筑成型。 <a class="header-anchor" href="#立园最具-西洋风格-的部分-几乎都靠钢筋混凝土现浇实现。包括门厅立柱、回廊拱券、二层阳台、挑檐、天花梁板、宝瓶式栏杆、装饰性柱头与线脚等-全部为现场支模、绑扎钢筋、一次性浇筑成型。" aria-label="Permalink to &quot;立园最具“西洋风格”的部分，几乎都靠钢筋混凝土现浇实现。包括门厅立柱、回廊拱券、二层阳台、挑檐、天花梁板、宝瓶式栏杆、装饰性柱头与线脚等，全部为现场支模、绑扎钢筋、一次性浇筑成型。&quot;">​</a></h1><h1 id="这种构造在20世纪20年代属于先进技术-由华侨从国外带回。它最大的优势是可以做出砖、石难以实现的弧形、曲面、浮雕、镂空、细长柱等造型-让西式柱式、拱券、山花、涡卷装饰得以落地。我们在现场能清晰看到" tabindex="-1">这种构造在20世纪20年代属于先进技术，由华侨从国外带回。它最大的优势是可以做出砖、石难以实现的弧形、曲面、浮雕、镂空、细长柱等造型，让西式柱式、拱券、山花、涡卷装饰得以落地。我们在现场能清晰看到： <a class="header-anchor" href="#这种构造在20世纪20年代属于先进技术-由华侨从国外带回。它最大的优势是可以做出砖、石难以实现的弧形、曲面、浮雕、镂空、细长柱等造型-让西式柱式、拱券、山花、涡卷装饰得以落地。我们在现场能清晰看到" aria-label="Permalink to &quot;这种构造在20世纪20年代属于先进技术，由华侨从国外带回。它最大的优势是可以做出砖、石难以实现的弧形、曲面、浮雕、镂空、细长柱等造型，让西式柱式、拱券、山花、涡卷装饰得以落地。我们在现场能清晰看到：&quot;">​</a></h1><h1 id="•-混凝土表面留有木板模板的条纹痕迹" tabindex="-1">• 混凝土表面留有木板模板的条纹痕迹； <a class="header-anchor" href="#•-混凝土表面留有木板模板的条纹痕迹" aria-label="Permalink to &quot;• 混凝土表面留有木板模板的条纹痕迹；&quot;">​</a></h1><h1 id="•-梁柱与墙体交接处一体浇筑、衔接自然" tabindex="-1">• 梁柱与墙体交接处一体浇筑、衔接自然； <a class="header-anchor" href="#•-梁柱与墙体交接处一体浇筑、衔接自然" aria-label="Permalink to &quot;• 梁柱与墙体交接处一体浇筑、衔接自然；&quot;">​</a></h1><h1 id="•-栏杆、浮雕、线脚无明显拼接缝-整体性很强。" tabindex="-1">• 栏杆、浮雕、线脚无明显拼接缝，整体性很强。 <a class="header-anchor" href="#•-栏杆、浮雕、线脚无明显拼接缝-整体性很强。" aria-label="Permalink to &quot;• 栏杆、浮雕、线脚无明显拼接缝，整体性很强。&quot;">​</a></h1><h1 id="混凝土结构与下方砖砌体结合紧密-共同受力-既保证大跨度、大挑出安全-又实现立面丰富造型-是立园构造上最关键的技术特征。" tabindex="-1">混凝土结构与下方砖砌体结合紧密，共同受力，既保证大跨度、大挑出安全，又实现立面丰富造型，是立园构造上最关键的技术特征。 <a class="header-anchor" href="#混凝土结构与下方砖砌体结合紧密-共同受力-既保证大跨度、大挑出安全-又实现立面丰富造型-是立园构造上最关键的技术特征。" aria-label="Permalink to &quot;混凝土结构与下方砖砌体结合紧密，共同受力，既保证大跨度、大挑出安全，又实现立面丰富造型，是立园构造上最关键的技术特征。&quot;">​</a></h1><h1 id="三-楼梯与地面-石材、混凝土、砖组合" tabindex="-1">（三）楼梯与地面：石材、混凝土、砖组合 <a class="header-anchor" href="#三-楼梯与地面-石材、混凝土、砖组合" aria-label="Permalink to &quot;（三）楼梯与地面：石材、混凝土、砖组合&quot;">​</a></h1><h1 id="室内主楼梯多为钢筋混凝土梯板-踏步面水泥砂浆抹面-边缘做圆角防滑处理-梯段侧边与墙体连为一体。部分次要楼梯与室外台阶则采用花岗岩条石-石材厚重、耐磨、抗压-适合人流踩踏与室外暴露环境。" tabindex="-1">室内主楼梯多为钢筋混凝土梯板，踏步面水泥砂浆抹面，边缘做圆角防滑处理，梯段侧边与墙体连为一体。部分次要楼梯与室外台阶则采用花岗岩条石，石材厚重、耐磨、抗压，适合人流踩踏与室外暴露环境。 <a class="header-anchor" href="#室内主楼梯多为钢筋混凝土梯板-踏步面水泥砂浆抹面-边缘做圆角防滑处理-梯段侧边与墙体连为一体。部分次要楼梯与室外台阶则采用花岗岩条石-石材厚重、耐磨、抗压-适合人流踩踏与室外暴露环境。" aria-label="Permalink to &quot;室内主楼梯多为钢筋混凝土梯板，踏步面水泥砂浆抹面，边缘做圆角防滑处理，梯段侧边与墙体连为一体。部分次要楼梯与室外台阶则采用花岗岩条石，石材厚重、耐磨、抗压，适合人流踩踏与室外暴露环境。&quot;">​</a></h1><h1 id="楼梯平台、走廊、厅堂等高频使用区域-地面多用水磨石或水泥砂浆面层-局部做简单分格线-整体坚固、易清洁、防潮-非常适合岭南潮湿环境。" tabindex="-1">楼梯平台、走廊、厅堂等高频使用区域，地面多用水磨石或水泥砂浆面层，局部做简单分格线，整体坚固、易清洁、防潮，非常适合岭南潮湿环境。 <a class="header-anchor" href="#楼梯平台、走廊、厅堂等高频使用区域-地面多用水磨石或水泥砂浆面层-局部做简单分格线-整体坚固、易清洁、防潮-非常适合岭南潮湿环境。" aria-label="Permalink to &quot;楼梯平台、走廊、厅堂等高频使用区域，地面多用水磨石或水泥砂浆面层，局部做简单分格线，整体坚固、易清洁、防潮，非常适合岭南潮湿环境。&quot;">​</a></h1><h1 id="三、外立面材料与立面构造" tabindex="-1">三、外立面材料与立面构造 <a class="header-anchor" href="#三、外立面材料与立面构造" aria-label="Permalink to &quot;三、外立面材料与立面构造&quot;">​</a></h1><h1 id="立园外立面材料层次清晰-主体抹灰、重点石材、局部木作与铁艺搭配-风格统一又富有变化-我们在现场逐段观察记录如下。" tabindex="-1">立园外立面材料层次清晰，主体抹灰、重点石材、局部木作与铁艺搭配，风格统一又富有变化，我们在现场逐段观察记录如下。 <a class="header-anchor" href="#立园外立面材料层次清晰-主体抹灰、重点石材、局部木作与铁艺搭配-风格统一又富有变化-我们在现场逐段观察记录如下。" aria-label="Permalink to &quot;立园外立面材料层次清晰，主体抹灰、重点石材、局部木作与铁艺搭配，风格统一又富有变化，我们在现场逐段观察记录如下。&quot;">​</a></h1><h1 id="一-外墙主体-水泥砂浆抹灰" tabindex="-1">（一）外墙主体：水泥砂浆抹灰 <a class="header-anchor" href="#一-外墙主体-水泥砂浆抹灰" aria-label="Permalink to &quot;（一）外墙主体：水泥砂浆抹灰&quot;">​</a></h1><h1 id="建筑外墙大面积采用水泥砂浆抹灰-面层为浅米黄色、浅灰色-质感平整、朴素、大气。这种做法成本适中、施工便捷、整体感强-是当时洋楼、公馆最主流的外墙做法。" tabindex="-1">建筑外墙大面积采用水泥砂浆抹灰，面层为浅米黄色、浅灰色，质感平整、朴素、大气。这种做法成本适中、施工便捷、整体感强，是当时洋楼、公馆最主流的外墙做法。 <a class="header-anchor" href="#建筑外墙大面积采用水泥砂浆抹灰-面层为浅米黄色、浅灰色-质感平整、朴素、大气。这种做法成本适中、施工便捷、整体感强-是当时洋楼、公馆最主流的外墙做法。" aria-label="Permalink to &quot;建筑外墙大面积采用水泥砂浆抹灰，面层为浅米黄色、浅灰色，质感平整、朴素、大气。这种做法成本适中、施工便捷、整体感强，是当时洋楼、公馆最主流的外墙做法。&quot;">​</a></h1><h1 id="经过近百年日晒雨淋-墙面留下明显岁月痕迹-雨水流淌形成的竖向水痕、局部抹灰空鼓剥落、边角轻微风化、植物附着留下的印记。这些不是破坏-而是历史层积-也真实反映了抹灰面层在岭南气候下的老化特征。" tabindex="-1">经过近百年日晒雨淋，墙面留下明显岁月痕迹：雨水流淌形成的竖向水痕、局部抹灰空鼓剥落、边角轻微风化、植物附着留下的印记。这些不是破坏，而是历史层积，也真实反映了抹灰面层在岭南气候下的老化特征。 <a class="header-anchor" href="#经过近百年日晒雨淋-墙面留下明显岁月痕迹-雨水流淌形成的竖向水痕、局部抹灰空鼓剥落、边角轻微风化、植物附着留下的印记。这些不是破坏-而是历史层积-也真实反映了抹灰面层在岭南气候下的老化特征。" aria-label="Permalink to &quot;经过近百年日晒雨淋，墙面留下明显岁月痕迹：雨水流淌形成的竖向水痕、局部抹灰空鼓剥落、边角轻微风化、植物附着留下的印记。这些不是破坏，而是历史层积，也真实反映了抹灰面层在岭南气候下的老化特征。&quot;">​</a></h1><h1 id="二-重点部位-花岗岩石材" tabindex="-1">（二）重点部位：花岗岩石材 <a class="header-anchor" href="#二-重点部位-花岗岩石材" aria-label="Permalink to &quot;（二）重点部位：花岗岩石材&quot;">​</a></h1><h1 id="在受力、防水、装饰关键部位-大量使用本地花岗岩-主要位置包括" tabindex="-1">在受力、防水、装饰关键部位，大量使用本地花岗岩，主要位置包括： <a class="header-anchor" href="#在受力、防水、装饰关键部位-大量使用本地花岗岩-主要位置包括" aria-label="Permalink to &quot;在受力、防水、装饰关键部位，大量使用本地花岗岩，主要位置包括：&quot;">​</a></h1><h1 id="•-柱础、立柱基座" tabindex="-1">• 柱础、立柱基座； <a class="header-anchor" href="#•-柱础、立柱基座" aria-label="Permalink to &quot;• 柱础、立柱基座；&quot;">​</a></h1><h1 id="•-门窗边框、窗台、窗楣" tabindex="-1">• 门窗边框、窗台、窗楣； <a class="header-anchor" href="#•-门窗边框、窗台、窗楣" aria-label="Permalink to &quot;• 门窗边框、窗台、窗楣；&quot;">​</a></h1><h1 id="•-外墙勒脚、台阶、压顶" tabindex="-1">• 外墙勒脚、台阶、压顶； <a class="header-anchor" href="#•-外墙勒脚、台阶、压顶" aria-label="Permalink to &quot;• 外墙勒脚、台阶、压顶；&quot;">​</a></h1><h1 id="•-门头重点装饰线条。" tabindex="-1">• 门头重点装饰线条。 <a class="header-anchor" href="#•-门头重点装饰线条。" aria-label="Permalink to &quot;• 门头重点装饰线条。&quot;">​</a></h1><h1 id="花岗岩质地坚硬、耐水耐腐、不易风化-颜色偏灰白-与黄色抹灰墙面形成柔和对比。石材为打磨面-接缝细密-采用干砌与坐浆结合-拼接工整-稳定性强。我们在立柱底部看到石材与混凝土柱身衔接自然-受力明确-构造逻辑很清晰。" tabindex="-1">花岗岩质地坚硬、耐水耐腐、不易风化，颜色偏灰白，与黄色抹灰墙面形成柔和对比。石材为打磨面，接缝细密，采用干砌与坐浆结合，拼接工整，稳定性强。我们在立柱底部看到石材与混凝土柱身衔接自然，受力明确，构造逻辑很清晰。 <a class="header-anchor" href="#花岗岩质地坚硬、耐水耐腐、不易风化-颜色偏灰白-与黄色抹灰墙面形成柔和对比。石材为打磨面-接缝细密-采用干砌与坐浆结合-拼接工整-稳定性强。我们在立柱底部看到石材与混凝土柱身衔接自然-受力明确-构造逻辑很清晰。" aria-label="Permalink to &quot;花岗岩质地坚硬、耐水耐腐、不易风化，颜色偏灰白，与黄色抹灰墙面形成柔和对比。石材为打磨面，接缝细密，采用干砌与坐浆结合，拼接工整，稳定性强。我们在立柱底部看到石材与混凝土柱身衔接自然，受力明确，构造逻辑很清晰。&quot;">​</a></h1><h1 id="三-门窗系统-木框玻璃-百叶-铁艺防护" tabindex="-1">（三）门窗系统：木框玻璃+百叶+铁艺防护 <a class="header-anchor" href="#三-门窗系统-木框玻璃-百叶-铁艺防护" aria-label="Permalink to &quot;（三）门窗系统：木框玻璃+百叶+铁艺防护&quot;">​</a></h1><h1 id="门窗是立园中西融合最直观的部位。" tabindex="-1">门窗是立园中西融合最直观的部位。 <a class="header-anchor" href="#门窗是立园中西融合最直观的部位。" aria-label="Permalink to &quot;门窗是立园中西融合最直观的部位。&quot;">​</a></h1><h1 id="•-窗框-以实木为主-榫卯制作-坚固耐用" tabindex="-1">• 窗框：以实木为主，榫卯制作，坚固耐用； <a class="header-anchor" href="#•-窗框-以实木为主-榫卯制作-坚固耐用" aria-label="Permalink to &quot;• 窗框：以实木为主，榫卯制作，坚固耐用；&quot;">​</a></h1><h1 id="•-玻璃-单层清玻璃-满足采光" tabindex="-1">• 玻璃：单层清玻璃，满足采光； <a class="header-anchor" href="#•-玻璃-单层清玻璃-满足采光" aria-label="Permalink to &quot;• 玻璃：单层清玻璃，满足采光；&quot;">​</a></h1><h1 id="•-外遮阳-多数窗户配有木质百叶-可开启、可调节-遮阳通风-是岭南应对日晒的实用构造" tabindex="-1">• 外遮阳：多数窗户配有木质百叶，可开启、可调节，遮阳通风，是岭南应对日晒的实用构造； <a class="header-anchor" href="#•-外遮阳-多数窗户配有木质百叶-可开启、可调节-遮阳通风-是岭南应对日晒的实用构造" aria-label="Permalink to &quot;• 外遮阳：多数窗户配有木质百叶，可开启、可调节，遮阳通风，是岭南应对日晒的实用构造；&quot;">​</a></h1><h1 id="•-安全防护-窗外加铁艺栅栏-铁件横竖线条简洁-焊接固定-兼具防御与装饰。" tabindex="-1">• 安全防护：窗外加铁艺栅栏，铁件横竖线条简洁，焊接固定，兼具防御与装饰。 <a class="header-anchor" href="#•-安全防护-窗外加铁艺栅栏-铁件横竖线条简洁-焊接固定-兼具防御与装饰。" aria-label="Permalink to &quot;• 安全防护：窗外加铁艺栅栏，铁件横竖线条简洁，焊接固定，兼具防御与装饰。&quot;">​</a></h1><h1 id="门窗四周均做混凝土或石材窗套线脚-呈阶梯状层层退出-既遮挡雨水、保护洞口-又强化西式立面构图-线条挺拔、比例匀称。" tabindex="-1">门窗四周均做混凝土或石材窗套线脚，呈阶梯状层层退出，既遮挡雨水、保护洞口，又强化西式立面构图，线条挺拔、比例匀称。 <a class="header-anchor" href="#门窗四周均做混凝土或石材窗套线脚-呈阶梯状层层退出-既遮挡雨水、保护洞口-又强化西式立面构图-线条挺拔、比例匀称。" aria-label="Permalink to &quot;门窗四周均做混凝土或石材窗套线脚，呈阶梯状层层退出，既遮挡雨水、保护洞口，又强化西式立面构图，线条挺拔、比例匀称。&quot;">​</a></h1><h1 id="四-檐口、栏板、山花-混凝土预制与现浇" tabindex="-1">（四）檐口、栏板、山花：混凝土预制与现浇 <a class="header-anchor" href="#四-檐口、栏板、山花-混凝土预制与现浇" aria-label="Permalink to &quot;（四）檐口、栏板、山花：混凝土预制与现浇&quot;">​</a></h1><h1 id="屋顶檐口、阳台栏板、墙面山花装饰-全部为混凝土现浇或预制拼装。" tabindex="-1">屋顶檐口、阳台栏板、墙面山花装饰，全部为混凝土现浇或预制拼装。 <a class="header-anchor" href="#屋顶檐口、阳台栏板、墙面山花装饰-全部为混凝土现浇或预制拼装。" aria-label="Permalink to &quot;屋顶檐口、阳台栏板、墙面山花装饰，全部为混凝土现浇或预制拼装。&quot;">​</a></h1><h1 id="•-檐口下方有托臂、涡卷、卷草纹等西式浮雕" tabindex="-1">• 檐口下方有托臂、涡卷、卷草纹等西式浮雕； <a class="header-anchor" href="#•-檐口下方有托臂、涡卷、卷草纹等西式浮雕" aria-label="Permalink to &quot;• 檐口下方有托臂、涡卷、卷草纹等西式浮雕；&quot;">​</a></h1><h1 id="•-阳台栏杆为宝瓶柱式-镂空通透-轻巧美观" tabindex="-1">• 阳台栏杆为宝瓶柱式，镂空通透，轻巧美观； <a class="header-anchor" href="#•-阳台栏杆为宝瓶柱式-镂空通透-轻巧美观" aria-label="Permalink to &quot;• 阳台栏杆为宝瓶柱式，镂空通透，轻巧美观；&quot;">​</a></h1><h1 id="•-山花部位做几何形与花卉浮雕-突出入口仪式感。" tabindex="-1">• 山花部位做几何形与花卉浮雕，突出入口仪式感。 <a class="header-anchor" href="#•-山花部位做几何形与花卉浮雕-突出入口仪式感。" aria-label="Permalink to &quot;• 山花部位做几何形与花卉浮雕，突出入口仪式感。&quot;">​</a></h1><h1 id="这些构件模具痕迹明显-整体感强-是立园-西式表皮-的主要载体。" tabindex="-1">这些构件模具痕迹明显，整体感强，是立园“西式表皮”的主要载体。 <a class="header-anchor" href="#这些构件模具痕迹明显-整体感强-是立园-西式表皮-的主要载体。" aria-label="Permalink to &quot;这些构件模具痕迹明显，整体感强，是立园“西式表皮”的主要载体。&quot;">​</a></h1><h1 id="四、室内构造与装饰材料" tabindex="-1">四、室内构造与装饰材料 <a class="header-anchor" href="#四、室内构造与装饰材料" aria-label="Permalink to &quot;四、室内构造与装饰材料&quot;">​</a></h1><h1 id="进入室内-我们能更清楚看到立园在天花、柱式、墙裙、线脚上的材料与构造做法-同样以务实为主-装饰适度-不浮夸。" tabindex="-1">进入室内，我们能更清楚看到立园在天花、柱式、墙裙、线脚上的材料与构造做法，同样以务实为主，装饰适度，不浮夸。 <a class="header-anchor" href="#进入室内-我们能更清楚看到立园在天花、柱式、墙裙、线脚上的材料与构造做法-同样以务实为主-装饰适度-不浮夸。" aria-label="Permalink to &quot;进入室内，我们能更清楚看到立园在天花、柱式、墙裙、线脚上的材料与构造做法，同样以务实为主，装饰适度，不浮夸。&quot;">​</a></h1><h1 id="一-室内柱式-砖砌-混凝土基底-抹灰塑形" tabindex="-1">（一）室内柱式：砖砌/混凝土基底+抹灰塑形 <a class="header-anchor" href="#一-室内柱式-砖砌-混凝土基底-抹灰塑形" aria-label="Permalink to &quot;（一）室内柱式：砖砌/混凝土基底+抹灰塑形&quot;">​</a></h1><h1 id="室内廊柱、壁柱有两种做法" tabindex="-1">室内廊柱、壁柱有两种做法： <a class="header-anchor" href="#室内廊柱、壁柱有两种做法" aria-label="Permalink to &quot;室内廊柱、壁柱有两种做法：&quot;">​</a></h1><h1 id="•-圆形廊柱-多为钢筋混凝土现浇-表面打磨平整-再做抹灰与涂料" tabindex="-1">• 圆形廊柱：多为钢筋混凝土现浇，表面打磨平整，再做抹灰与涂料； <a class="header-anchor" href="#•-圆形廊柱-多为钢筋混凝土现浇-表面打磨平整-再做抹灰与涂料" aria-label="Permalink to &quot;• 圆形廊柱：多为钢筋混凝土现浇，表面打磨平整，再做抹灰与涂料；&quot;">​</a></h1><h1 id="•-方形壁柱-多为砖砌凸出-表面水泥砂浆做竖向凹槽线条-模拟西式柱身。" tabindex="-1">• 方形壁柱：多为砖砌凸出，表面水泥砂浆做竖向凹槽线条，模拟西式柱身。 <a class="header-anchor" href="#•-方形壁柱-多为砖砌凸出-表面水泥砂浆做竖向凹槽线条-模拟西式柱身。" aria-label="Permalink to &quot;• 方形壁柱：多为砖砌凸出，表面水泥砂浆做竖向凹槽线条，模拟西式柱身。&quot;">​</a></h1><h1 id="柱头以科林斯茛苕叶、爱奥尼涡卷为主-用水泥或石膏现场塑形、浮雕成型-花纹清晰、立体感强。柱底一律配石材柱础-稳定、防潮、受力合理。" tabindex="-1">柱头以科林斯茛苕叶、爱奥尼涡卷为主，用水泥或石膏现场塑形、浮雕成型，花纹清晰、立体感强。柱底一律配石材柱础，稳定、防潮、受力合理。 <a class="header-anchor" href="#柱头以科林斯茛苕叶、爱奥尼涡卷为主-用水泥或石膏现场塑形、浮雕成型-花纹清晰、立体感强。柱底一律配石材柱础-稳定、防潮、受力合理。" aria-label="Permalink to &quot;柱头以科林斯茛苕叶、爱奥尼涡卷为主，用水泥或石膏现场塑形、浮雕成型，花纹清晰、立体感强。柱底一律配石材柱础，稳定、防潮、受力合理。&quot;">​</a></h1><h1 id="二-天花藻井与线脚-混凝土基底-石膏-水泥预制" tabindex="-1">（二）天花藻井与线脚：混凝土基底+石膏/水泥预制 <a class="header-anchor" href="#二-天花藻井与线脚-混凝土基底-石膏-水泥预制" aria-label="Permalink to &quot;（二）天花藻井与线脚：混凝土基底+石膏/水泥预制&quot;">​</a></h1><h1 id="室内天花为混凝土平顶-不做复杂吊顶-依靠多层线脚围合出方形、菱形藻井。" tabindex="-1">室内天花为混凝土平顶，不做复杂吊顶，依靠多层线脚围合出方形、菱形藻井。 <a class="header-anchor" href="#室内天花为混凝土平顶-不做复杂吊顶-依靠多层线脚围合出方形、菱形藻井。" aria-label="Permalink to &quot;室内天花为混凝土平顶，不做复杂吊顶，依靠多层线脚围合出方形、菱形藻井。&quot;">​</a></h1><h1 id="•-基层-混凝土结构板" tabindex="-1">• 基层：混凝土结构板； <a class="header-anchor" href="#•-基层-混凝土结构板" aria-label="Permalink to &quot;• 基层：混凝土结构板；&quot;">​</a></h1><h1 id="•-中层-水泥砂浆找平" tabindex="-1">• 中层：水泥砂浆找平； <a class="header-anchor" href="#•-中层-水泥砂浆找平" aria-label="Permalink to &quot;• 中层：水泥砂浆找平；&quot;">​</a></h1><h1 id="•-面层-预制石膏-水泥线条粘贴-拼接组合" tabindex="-1">• 面层：预制石膏/水泥线条粘贴，拼接组合； <a class="header-anchor" href="#•-面层-预制石膏-水泥线条粘贴-拼接组合" aria-label="Permalink to &quot;• 面层：预制石膏/水泥线条粘贴，拼接组合；&quot;">​</a></h1><h1 id="•-中心-浮雕花饰-现场安装后彩绘。" tabindex="-1">• 中心：浮雕花饰，现场安装后彩绘。 <a class="header-anchor" href="#•-中心-浮雕花饰-现场安装后彩绘。" aria-label="Permalink to &quot;• 中心：浮雕花饰，现场安装后彩绘。&quot;">​</a></h1><h1 id="我们能清楚看到拼接缝、粘贴痕迹、修补痕迹-部分彩绘因年代久远出现褪色、起皮-但整体构图完整、色彩沉稳-中西纹样并用-是侨乡室内装饰的典型做法。" tabindex="-1">我们能清楚看到拼接缝、粘贴痕迹、修补痕迹，部分彩绘因年代久远出现褪色、起皮，但整体构图完整、色彩沉稳，中西纹样并用，是侨乡室内装饰的典型做法。 <a class="header-anchor" href="#我们能清楚看到拼接缝、粘贴痕迹、修补痕迹-部分彩绘因年代久远出现褪色、起皮-但整体构图完整、色彩沉稳-中西纹样并用-是侨乡室内装饰的典型做法。" aria-label="Permalink to &quot;我们能清楚看到拼接缝、粘贴痕迹、修补痕迹，部分彩绘因年代久远出现褪色、起皮，但整体构图完整、色彩沉稳，中西纹样并用，是侨乡室内装饰的典型做法。&quot;">​</a></h1><h1 id="三-墙裙与踢脚-水磨石-水刷石" tabindex="-1">（三）墙裙与踢脚：水磨石/水刷石 <a class="header-anchor" href="#三-墙裙与踢脚-水磨石-水刷石" aria-label="Permalink to &quot;（三）墙裙与踢脚：水磨石/水刷石&quot;">​</a></h1><h1 id="走廊、厅堂等易碰撞、易潮湿位置-墙面下部做墙裙-材料以水磨石、水刷石为主。面层颗粒均匀、硬度高、耐擦洗、防潮效果好-高度大约在1米左右-构造层次为-基层砖砌体→水泥砂浆结合层→石粒面层。这是民国时期岭南公共与居住建筑非常普及的构造做法-实用性极强。" tabindex="-1">走廊、厅堂等易碰撞、易潮湿位置，墙面下部做墙裙，材料以水磨石、水刷石为主。面层颗粒均匀、硬度高、耐擦洗、防潮效果好，高度大约在1米左右，构造层次为：基层砖砌体→水泥砂浆结合层→石粒面层。这是民国时期岭南公共与居住建筑非常普及的构造做法，实用性极强。 <a class="header-anchor" href="#走廊、厅堂等易碰撞、易潮湿位置-墙面下部做墙裙-材料以水磨石、水刷石为主。面层颗粒均匀、硬度高、耐擦洗、防潮效果好-高度大约在1米左右-构造层次为-基层砖砌体→水泥砂浆结合层→石粒面层。这是民国时期岭南公共与居住建筑非常普及的构造做法-实用性极强。" aria-label="Permalink to &quot;走廊、厅堂等易碰撞、易潮湿位置，墙面下部做墙裙，材料以水磨石、水刷石为主。面层颗粒均匀、硬度高、耐擦洗、防潮效果好，高度大约在1米左右，构造层次为：基层砖砌体→水泥砂浆结合层→石粒面层。这是民国时期岭南公共与居住建筑非常普及的构造做法，实用性极强。&quot;">​</a></h1><h1 id="五、构件连接方式与施工痕迹-实地观察重点" tabindex="-1">五、构件连接方式与施工痕迹（实地观察重点） <a class="header-anchor" href="#五、构件连接方式与施工痕迹-实地观察重点" aria-label="Permalink to &quot;五、构件连接方式与施工痕迹（实地观察重点）&quot;">​</a></h1><h1 id="本次构造调研核心是看怎么连、怎么做、痕迹在哪-我们在现场重点记录了以下几类连接方式。" tabindex="-1">本次构造调研核心是看怎么连、怎么做、痕迹在哪，我们在现场重点记录了以下几类连接方式。 <a class="header-anchor" href="#本次构造调研核心是看怎么连、怎么做、痕迹在哪-我们在现场重点记录了以下几类连接方式。" aria-label="Permalink to &quot;本次构造调研核心是看怎么连、怎么做、痕迹在哪，我们在现场重点记录了以下几类连接方式。&quot;">​</a></h1><h1 id="一-砌筑连接-砖与砖、砖与混凝土" tabindex="-1">（一）砌筑连接：砖与砖、砖与混凝土 <a class="header-anchor" href="#一-砌筑连接-砖与砖、砖与混凝土" aria-label="Permalink to &quot;（一）砌筑连接：砖与砖、砖与混凝土&quot;">​</a></h1><h1 id="青砖墙体以坐浆砌筑-灰缝横平竖直-搭接咬合规律-整体性好。砖墙与混凝土梁柱交接处-混凝土直接浇筑包裹或顶紧砖墙-界面清晰-受力传递直接。部分后砌隔墙可见轻微裂缝-属于正常变形痕迹。" tabindex="-1">青砖墙体以坐浆砌筑，灰缝横平竖直，搭接咬合规律，整体性好。砖墙与混凝土梁柱交接处，混凝土直接浇筑包裹或顶紧砖墙，界面清晰，受力传递直接。部分后砌隔墙可见轻微裂缝，属于正常变形痕迹。 <a class="header-anchor" href="#青砖墙体以坐浆砌筑-灰缝横平竖直-搭接咬合规律-整体性好。砖墙与混凝土梁柱交接处-混凝土直接浇筑包裹或顶紧砖墙-界面清晰-受力传递直接。部分后砌隔墙可见轻微裂缝-属于正常变形痕迹。" aria-label="Permalink to &quot;青砖墙体以坐浆砌筑，灰缝横平竖直，搭接咬合规律，整体性好。砖墙与混凝土梁柱交接处，混凝土直接浇筑包裹或顶紧砖墙，界面清晰，受力传递直接。部分后砌隔墙可见轻微裂缝，属于正常变形痕迹。&quot;">​</a></h1><h1 id="二-整体现浇连接-混凝土一体成型" tabindex="-1">（二）整体现浇连接：混凝土一体成型 <a class="header-anchor" href="#二-整体现浇连接-混凝土一体成型" aria-label="Permalink to &quot;（二）整体现浇连接：混凝土一体成型&quot;">​</a></h1><h1 id="拱券、柱头、栏板、檐口等装饰性构件-多为与结构一体现浇-没有后期拼装-因此线条流畅、形态完整。表面可见明显的模板印、振捣痕迹、收光痕迹-是判断现浇工艺最直接的依据。" tabindex="-1">拱券、柱头、栏板、檐口等装饰性构件，多为与结构一体现浇，没有后期拼装，因此线条流畅、形态完整。表面可见明显的模板印、振捣痕迹、收光痕迹，是判断现浇工艺最直接的依据。 <a class="header-anchor" href="#拱券、柱头、栏板、檐口等装饰性构件-多为与结构一体现浇-没有后期拼装-因此线条流畅、形态完整。表面可见明显的模板印、振捣痕迹、收光痕迹-是判断现浇工艺最直接的依据。" aria-label="Permalink to &quot;拱券、柱头、栏板、檐口等装饰性构件，多为与结构一体现浇，没有后期拼装，因此线条流畅、形态完整。表面可见明显的模板印、振捣痕迹、收光痕迹，是判断现浇工艺最直接的依据。&quot;">​</a></h1><h1 id="三-预制拼装-线脚、花饰、浮雕" tabindex="-1">（三）预制拼装：线脚、花饰、浮雕 <a class="header-anchor" href="#三-预制拼装-线脚、花饰、浮雕" aria-label="Permalink to &quot;（三）预制拼装：线脚、花饰、浮雕&quot;">​</a></h1><h1 id="室内大量线脚、花片为工厂预制-运到现场用砂浆粘贴、锚固-再补缝打磨。我们能看到" tabindex="-1">室内大量线脚、花片为工厂预制，运到现场用砂浆粘贴、锚固，再补缝打磨。我们能看到： <a class="header-anchor" href="#室内大量线脚、花片为工厂预制-运到现场用砂浆粘贴、锚固-再补缝打磨。我们能看到" aria-label="Permalink to &quot;室内大量线脚、花片为工厂预制，运到现场用砂浆粘贴、锚固，再补缝打磨。我们能看到：&quot;">​</a></h1><h1 id="•-拼接缝隙整齐" tabindex="-1">• 拼接缝隙整齐； <a class="header-anchor" href="#•-拼接缝隙整齐" aria-label="Permalink to &quot;• 拼接缝隙整齐；&quot;">​</a></h1><h1 id="•-转角处切割对接" tabindex="-1">• 转角处切割对接； <a class="header-anchor" href="#•-转角处切割对接" aria-label="Permalink to &quot;• 转角处切割对接；&quot;">​</a></h1><h1 id="•-局部脱落处露出粘贴界面。" tabindex="-1">• 局部脱落处露出粘贴界面。 <a class="header-anchor" href="#•-局部脱落处露出粘贴界面。" aria-label="Permalink to &quot;• 局部脱落处露出粘贴界面。&quot;">​</a></h1><h1 id="这种做法效率高、装饰效果统一-是当时常用的工业化装饰手段。" tabindex="-1">这种做法效率高、装饰效果统一，是当时常用的工业化装饰手段。 <a class="header-anchor" href="#这种做法效率高、装饰效果统一-是当时常用的工业化装饰手段。" aria-label="Permalink to &quot;这种做法效率高、装饰效果统一，是当时常用的工业化装饰手段。&quot;">​</a></h1><h1 id="四-石材干砌与坐浆" tabindex="-1">（四）石材干砌与坐浆 <a class="header-anchor" href="#四-石材干砌与坐浆" aria-label="Permalink to &quot;（四）石材干砌与坐浆&quot;">​</a></h1><h1 id="石材构件以干砌咬合为主-局部坐浆加固-接缝严密-稳定性高。台阶、勒脚、柱础等部位石材磨损自然-包浆明显-是长期使用留下的真实痕迹。" tabindex="-1">石材构件以干砌咬合为主，局部坐浆加固，接缝严密，稳定性高。台阶、勒脚、柱础等部位石材磨损自然，包浆明显，是长期使用留下的真实痕迹。 <a class="header-anchor" href="#石材构件以干砌咬合为主-局部坐浆加固-接缝严密-稳定性高。台阶、勒脚、柱础等部位石材磨损自然-包浆明显-是长期使用留下的真实痕迹。" aria-label="Permalink to &quot;石材构件以干砌咬合为主，局部坐浆加固，接缝严密，稳定性高。台阶、勒脚、柱础等部位石材磨损自然，包浆明显，是长期使用留下的真实痕迹。&quot;">​</a></h1><h1 id="五-木作与铁艺-榫卯、焊接、预埋" tabindex="-1">（五）木作与铁艺：榫卯、焊接、预埋 <a class="header-anchor" href="#五-木作与铁艺-榫卯、焊接、预埋" aria-label="Permalink to &quot;（五）木作与铁艺：榫卯、焊接、预埋&quot;">​</a></h1><h1 id="木门窗采用传统榫卯-框体与墙体用预埋木砖固定-牢固耐久。铁艺栅栏为钢材焊接-与预埋在混凝土里的铁件连接-防护可靠、构造简单。" tabindex="-1">木门窗采用传统榫卯，框体与墙体用预埋木砖固定，牢固耐久。铁艺栅栏为钢材焊接，与预埋在混凝土里的铁件连接，防护可靠、构造简单。 <a class="header-anchor" href="#木门窗采用传统榫卯-框体与墙体用预埋木砖固定-牢固耐久。铁艺栅栏为钢材焊接-与预埋在混凝土里的铁件连接-防护可靠、构造简单。" aria-label="Permalink to &quot;木门窗采用传统榫卯，框体与墙体用预埋木砖固定，牢固耐久。铁艺栅栏为钢材焊接，与预埋在混凝土里的铁件连接，防护可靠、构造简单。&quot;">​</a></h1><h1 id="六、材料与构造反映的建造逻辑-总结性观察" tabindex="-1">六、材料与构造反映的建造逻辑（总结性观察） <a class="header-anchor" href="#六、材料与构造反映的建造逻辑-总结性观察" aria-label="Permalink to &quot;六、材料与构造反映的建造逻辑（总结性观察）&quot;">​</a></h1><h1 id="通过实地走看、触摸、比对、拍照-我们总结立园在材料与构造上的真实逻辑-而非书本套话" tabindex="-1">通过实地走看、触摸、比对、拍照，我们总结立园在材料与构造上的真实逻辑，而非书本套话： <a class="header-anchor" href="#通过实地走看、触摸、比对、拍照-我们总结立园在材料与构造上的真实逻辑-而非书本套话" aria-label="Permalink to &quot;通过实地走看、触摸、比对、拍照，我们总结立园在材料与构造上的真实逻辑，而非书本套话：&quot;">​</a></h1><h1 id="_1-安全第一-厚砖承重、石材基座、混凝土加固、铁艺防护-满足居住安全与防御需求。" tabindex="-1">1. 安全第一：厚砖承重、石材基座、混凝土加固、铁艺防护，满足居住安全与防御需求。 <a class="header-anchor" href="#_1-安全第一-厚砖承重、石材基座、混凝土加固、铁艺防护-满足居住安全与防御需求。" aria-label="Permalink to &quot;1\\. 安全第一：厚砖承重、石材基座、混凝土加固、铁艺防护，满足居住安全与防御需求。&quot;">​</a></h1><h1 id="_2-适应气候-厚墙隔热、百叶遮阳、墙裙防潮、石材勒脚、整体排水-完全针对岭南高温多雨。" tabindex="-1">2. 适应气候：厚墙隔热、百叶遮阳、墙裙防潮、石材勒脚、整体排水，完全针对岭南高温多雨。 <a class="header-anchor" href="#_2-适应气候-厚墙隔热、百叶遮阳、墙裙防潮、石材勒脚、整体排水-完全针对岭南高温多雨。" aria-label="Permalink to &quot;2\\. 适应气候：厚墙隔热、百叶遮阳、墙裙防潮、石材勒脚、整体排水，完全针对岭南高温多雨。&quot;">​</a></h1><h1 id="_3-技术务实-能用传统砖就用砖-需要造型就用混凝土-不盲目追求新技术-性价比高、可落地。" tabindex="-1">3. 技术务实：能用传统砖就用砖，需要造型就用混凝土，不盲目追求新技术，性价比高、可落地。 <a class="header-anchor" href="#_3-技术务实-能用传统砖就用砖-需要造型就用混凝土-不盲目追求新技术-性价比高、可落地。" aria-label="Permalink to &quot;3\\. 技术务实：能用传统砖就用砖，需要造型就用混凝土，不盲目追求新技术，性价比高、可落地。&quot;">​</a></h1><h1 id="_4-身份表达-用西洋柱式、线脚、拱券体现华侨视野与审美-用本土材料与工艺降低成本、便于施工。" tabindex="-1">4. 身份表达：用西洋柱式、线脚、拱券体现华侨视野与审美，用本土材料与工艺降低成本、便于施工。 <a class="header-anchor" href="#_4-身份表达-用西洋柱式、线脚、拱券体现华侨视野与审美-用本土材料与工艺降低成本、便于施工。" aria-label="Permalink to &quot;4\\. 身份表达：用西洋柱式、线脚、拱券体现华侨视野与审美，用本土材料与工艺降低成本、便于施工。&quot;">​</a></h1><h1 id="_5-耐久易维护-材料大多坚固、耐候、易清洁-适合长期使用与家族传承。" tabindex="-1">5. 耐久易维护：材料大多坚固、耐候、易清洁，适合长期使用与家族传承。 <a class="header-anchor" href="#_5-耐久易维护-材料大多坚固、耐候、易清洁-适合长期使用与家族传承。" aria-label="Permalink to &quot;5\\. 耐久易维护：材料大多坚固、耐候、易清洁，适合长期使用与家族传承。&quot;">​</a></h1><h1 id="现场最打动我们的不是-风格-而是每一种材料、每一个构造都有明确目的-承重、防潮、遮阳、通风、安全、美观-环环相扣-非常理性、非常接地气。" tabindex="-1">现场最打动我们的不是“风格”，而是每一种材料、每一个构造都有明确目的：承重、防潮、遮阳、通风、安全、美观，环环相扣，非常理性、非常接地气。 <a class="header-anchor" href="#现场最打动我们的不是-风格-而是每一种材料、每一个构造都有明确目的-承重、防潮、遮阳、通风、安全、美观-环环相扣-非常理性、非常接地气。" aria-label="Permalink to &quot;现场最打动我们的不是“风格”，而是每一种材料、每一个构造都有明确目的：承重、防潮、遮阳、通风、安全、美观，环环相扣，非常理性、非常接地气。&quot;">​</a></h1><h1 id="七、调研结语" tabindex="-1">七、调研结语 <a class="header-anchor" href="#七、调研结语" aria-label="Permalink to &quot;七、调研结语&quot;">​</a></h1><h1 id="本次开平立园实地构造调研-让我们从图纸之外真正-看懂-一座近代侨乡建筑。立园不是简单的-中式-西式-风格拼接-而是一套完整、自洽、高度适应地域环境的建造系统-主体以砖混保证安全与隔热-重点部位用混凝土实现造型-外立面以抹灰与石材形成层次-室内以线脚与彩绘提升氛围-所有构造做法都围绕功能、气候、成本、审美综合权衡。" tabindex="-1">本次开平立园实地构造调研，让我们从图纸之外真正“看懂”一座近代侨乡建筑。立园不是简单的“中式+西式”风格拼接，而是一套完整、自洽、高度适应地域环境的建造系统：主体以砖混保证安全与隔热，重点部位用混凝土实现造型，外立面以抹灰与石材形成层次，室内以线脚与彩绘提升氛围，所有构造做法都围绕功能、气候、成本、审美综合权衡。 <a class="header-anchor" href="#本次开平立园实地构造调研-让我们从图纸之外真正-看懂-一座近代侨乡建筑。立园不是简单的-中式-西式-风格拼接-而是一套完整、自洽、高度适应地域环境的建造系统-主体以砖混保证安全与隔热-重点部位用混凝土实现造型-外立面以抹灰与石材形成层次-室内以线脚与彩绘提升氛围-所有构造做法都围绕功能、气候、成本、审美综合权衡。" aria-label="Permalink to &quot;本次开平立园实地构造调研，让我们从图纸之外真正“看懂”一座近代侨乡建筑。立园不是简单的“中式+西式”风格拼接，而是一套完整、自洽、高度适应地域环境的建造系统：主体以砖混保证安全与隔热，重点部位用混凝土实现造型，外立面以抹灰与石材形成层次，室内以线脚与彩绘提升氛围，所有构造做法都围绕功能、气候、成本、审美综合权衡。&quot;">​</a></h1><h1 id="我们记录的每一种材料、每一类连接方式、每一处施工痕迹-都来自现场真实观察。这些内容不仅是课程作业-更是理解历史建筑、做地域化设计的重要基础。立园告诉我们-好的建筑不在于风格多华丽-而在于材料用得对、构造做得实、细节考虑到人、气候与生活。" tabindex="-1">我们记录的每一种材料、每一类连接方式、每一处施工痕迹，都来自现场真实观察。这些内容不仅是课程作业，更是理解历史建筑、做地域化设计的重要基础。立园告诉我们：好的建筑不在于风格多华丽，而在于材料用得对、构造做得实、细节考虑到人、气候与生活。 <a class="header-anchor" href="#我们记录的每一种材料、每一类连接方式、每一处施工痕迹-都来自现场真实观察。这些内容不仅是课程作业-更是理解历史建筑、做地域化设计的重要基础。立园告诉我们-好的建筑不在于风格多华丽-而在于材料用得对、构造做得实、细节考虑到人、气候与生活。" aria-label="Permalink to &quot;我们记录的每一种材料、每一类连接方式、每一处施工痕迹，都来自现场真实观察。这些内容不仅是课程作业，更是理解历史建筑、做地域化设计的重要基础。立园告诉我们：好的建筑不在于风格多华丽，而在于材料用得对、构造做得实、细节考虑到人、气候与生活。&quot;">​</a></h1><h1 id="未来在环境设计实践中-我们会继续保持这种-现场意识-多看、多摸、多问、多记-把真实建造逻辑融入设计-做出更扎实、更有温度、更接地气的空间作品。" tabindex="-1">未来在环境设计实践中，我们会继续保持这种“现场意识”，多看、多摸、多问、多记，把真实建造逻辑融入设计，做出更扎实、更有温度、更接地气的空间作品。 <a class="header-anchor" href="#未来在环境设计实践中-我们会继续保持这种-现场意识-多看、多摸、多问、多记-把真实建造逻辑融入设计-做出更扎实、更有温度、更接地气的空间作品。" aria-label="Permalink to &quot;未来在环境设计实践中，我们会继续保持这种“现场意识”，多看、多摸、多问、多记，把真实建造逻辑融入设计，做出更扎实、更有温度、更接地气的空间作品。&quot;">​</a></h1><h1 id="指导教师意见" tabindex="-1">指导教师意见： <a class="header-anchor" href="#指导教师意见" aria-label="Permalink to &quot;指导教师意见：&quot;">​</a></h1><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td>分项</td><td>分数</td></tr><tr><td>调研主目的意义</td><td></td></tr><tr><td>调研过程与内容</td><td></td></tr><tr><td>调研分析深度与专业适配性</td><td></td></tr><tr><td>心得体会与反思</td><td></td></tr><tr><td>总分</td><td></td></tr></tbody></table><p>签名：</p><p>2026 年 4 月 19 日</p><h1 id="说明" tabindex="-1">说明： <a class="header-anchor" href="#说明" aria-label="Permalink to &quot;说明：&quot;">​</a></h1><p>1. 专业调研报告字数不少于2500字，页数不够可以自行加页，但不能更改表格格式。</p><p>2. 开题报告字体为小四号，宋体（英文需用Times New Roman字体），行距为固定值20磅。</p><p>3. 彩色双面打印。</p>',102)])])}const q=e(o,[["render",i]]);export{u as __pageData,q as default};
